import{bQ as a,aL as d,u as r,G as e}from"./chunks/framework.D06dwy5q.js";const i="/kb/assets/01-single-point-failure.D7maA5Xe.png",s="/kb/assets/02-primary-standby-switch.CkbUomtL.png",n="/kb/assets/03-split-brain-quorum.B7Vr6eAs.png",l="/kb/assets/04-read-after-write-lag.DWIAyGlq.png",A=JSON.parse('{"title":"第 9 讲｜高可用架构","description":"","frontmatter":{},"headers":[],"relativePath":"00.互联网与架构基础/09-高可用架构.md","filePath":"00.互联网与架构基础/09-高可用架构.md","lastUpdated":null}'),o={name:"00.互联网与架构基础/09-高可用架构.md"};function h(p,t,b,u,c,g){return d(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="第-9-讲-高可用架构" tabindex="-1">第 9 讲｜高可用架构 <a class="header-anchor" href="#第-9-讲-高可用架构" aria-label="Permalink to &quot;第 9 讲｜高可用架构&quot;">​</a></h1><p>服务运行过程中,机器宕机、进程退出、磁盘写满、网络抖动、数据库不可写等问题随时可能发生。<strong>高可用(High Availability,HA)要解决的核心问题是:在这些故障真实发生时,服务对外仍能保持可用</strong>。</p><p>单机系统的根本风险是<strong>单点(Single Point of Failure,SPOF)</strong>——任何一个关键组件只有一份,坏了就全停。高可用架构的两个核心动作:<strong>消除单点 + 把切换做对</strong>。</p><p>本讲围绕高可用的核心概念展开:单点的识别、主备模式、故障发现机制、集群形态的差异、数据一致性问题、恢复确认与演练。</p><h2 id="一、单点的识别" tabindex="-1">一、单点的识别 <a class="header-anchor" href="#一、单点的识别" aria-label="Permalink to &quot;一、单点的识别&quot;">​</a></h2><p>任何&quot;只剩一个&quot;的关键对象都是单点。常见单点及其故障表现:</p><p><img src="'+i+'" alt="高可用首先要识别单点而不只是加副本"></p><table tabindex="0"><thead><tr><th>单点</th><th>故障后的现象</th></tr></thead><tbody><tr><td>单台 Web 服务器</td><td>页面和接口全部不可访问</td></tr><tr><td>单个负载均衡器</td><td>后端正常,但外部入口不可用</td></tr><tr><td>单个数据库主库</td><td>写入失败,所有写接口报错</td></tr><tr><td>单个 Redis</td><td>缓存、会话、限流、分布式锁全部异常</td></tr><tr><td>单条公网线路</td><td>外部访问中断,或部分地区访问异常</td></tr><tr><td>单个 DNS 配置</td><td>域名解析失败,全站不可达</td></tr><tr><td>单个机房</td><td>整个机房故障(电力、网络、空调)→ 全部服务停摆</td></tr><tr><td>单条网络链路</td><td>上游中断 → 某个网段无法访问</td></tr><tr><td>单台堡垒机</td><td>运维无法登录所有机器</td></tr></tbody></table><h3 id="单点不只是硬件" tabindex="-1">单点不只是硬件 <a class="header-anchor" href="#单点不只是硬件" aria-label="Permalink to &quot;单点不只是硬件&quot;">​</a></h3><p>单点的概念远不止&quot;一台机器&quot;——<strong>软件层、组织层、流程层都可能存在单点</strong>:</p><ul><li><strong>配置单点</strong>:某个关键配置只在一台机器上,丢了无法恢复</li><li><strong>密钥单点</strong>:加密私钥、证书、SSH 密钥只在一处保存</li><li><strong>知识单点</strong>:只有一个人懂某个系统,他离职/休假就没人能处理故障</li><li><strong>流程单点</strong>:某个变更必须通过某一个人审批,他不在就卡住</li></ul><p>高可用工作不只是&quot;加机器&quot;,还包括<strong>配置备份、知识沉淀、流程冗余</strong>。</p><h3 id="多副本不等于高可用" tabindex="-1">多副本不等于高可用 <a class="header-anchor" href="#多副本不等于高可用" aria-label="Permalink to &quot;多副本不等于高可用&quot;">​</a></h3><p>减少单点不是简单加一台机器摆在那儿。多出来的实例必须满足:</p><ul><li><strong>被入口发现并接入流量</strong> — 否则只是摆设</li><li><strong>坏掉时能被自动摘除</strong> — 否则用户请求会落到坏的实例</li><li><strong>角色切换后客户端能找到新主</strong> — 否则切换无效</li></ul><p>任何一项缺失,备用机器在真出事时不会自动接管,业务仍然会停。<strong>高可用是一整套机制,不只是多副本</strong>。</p><h2 id="二、主备模式" tabindex="-1">二、主备模式 <a class="header-anchor" href="#二、主备模式" aria-label="Permalink to &quot;二、主备模式&quot;">​</a></h2><p>主备(Active-Standby)是最容易理解的高可用方案:<strong>一台主节点对外服务,另一台备节点同步数据,主节点故障时备节点接管</strong>。</p><p><img src="'+s+'" alt="主备模式最难的是切换而不是多装一台"></p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20User%5B%22%E7%94%A8%E6%88%B7%22%5D%0A%20%20VIP%5B%22VIP%20%2F%20%E5%85%A5%E5%8F%A3%E5%9C%B0%E5%9D%80%3Cbr%2F%3E(%E6%BC%82%E6%B5%AE)%22%5D%0A%20%20Primary%5B%22%E4%B8%BB%E8%8A%82%E7%82%B9%3Cbr%2F%3E%E5%AF%B9%E5%A4%96%E6%9C%8D%E5%8A%A1%22%5D%0A%20%20Standby%5B%22%E5%A4%87%E8%8A%82%E7%82%B9%3Cbr%2F%3E%E6%95%B0%E6%8D%AE%E5%90%8C%E6%AD%A5%22%5D%0A%20%20Sync%5B%22%E5%90%8C%E6%AD%A5%E9%93%BE%E8%B7%AF%22%5D%0A%0A%20%20User%20--%3E%20VIP%0A%20%20VIP%20--%3E%20Primary%0A%20%20Primary%20-.-%3E%7C%22%E5%A4%8D%E5%88%B6%22%7C%20Sync%0A%20%20Sync%20-.-%3E%20Standby%0A"></div><p>主备模式在数据库、负载均衡、网关、存储系统中都很常见。</p><h3 id="主备的几种工作模式" tabindex="-1">主备的几种工作模式 <a class="header-anchor" href="#主备的几种工作模式" aria-label="Permalink to &quot;主备的几种工作模式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模式</th><th>备节点的状态</th><th>切换时间</th></tr></thead><tbody><tr><td>冷备(Cold Standby)</td><td>平时关机,故障时启动</td><td>慢(数分钟)</td></tr><tr><td>暖备(Warm Standby)</td><td>平时运行但不接流量,数据同步</td><td>中(秒到分钟)</td></tr><tr><td>热备(Hot Standby)</td><td>实时同步,可立即接管</td><td>快(秒级)</td></tr><tr><td>Active-Active(双活)</td><td>两边都对外服务</td><td>不需切换</td></tr></tbody></table><p>热备和双活的可用性更高,但实现复杂度也更高。多数业务系统采用热备:备节点持续同步数据,具备随时接管的能力。</p><h3 id="切换-主备最难的部分" tabindex="-1">切换:主备最难的部分 <a class="header-anchor" href="#切换-主备最难的部分" aria-label="Permalink to &quot;切换:主备最难的部分&quot;">​</a></h3><p>主备模式真正的难点是<strong>切换那一瞬间</strong>。切换有两类典型问题:</p><p><strong>问题 1:切得太慢</strong></p><p>故障发生到切换完成的时间越长,业务受影响时间越长。典型的切换流程:</p><ol><li>探测主节点不可用(健康检查失败超过阈值)</li><li>提升备节点为主</li><li>更新入口指向(VIP 漂移、DNS 切换、客户端重连)</li><li>验证写入恢复</li></ol><p>每一步都需要时间,合起来可能从几秒到几分钟。**RTO(Recovery Time Objective)**就是衡量&quot;故障到恢复&quot;耗时的指标。</p><p><strong>问题 2:脑裂(Split Brain)</strong></p><p>如果<strong>两个节点同时认为自己是主</strong>,各自接受写请求,数据分别写到两边,后续合并几乎不可能,可能丢数据。</p><p>脑裂的典型成因:</p><ul><li>主节点其实没死,只是网络分区(主节点与监控之间网络断了,但主节点本身还在服务客户端)</li><li>备节点没收到主节点心跳就抢了主</li><li>同时存在两个&quot;主&quot;,数据双写</li></ul><h3 id="keepalived-vip-经典的主备入口方案" tabindex="-1">Keepalived + VIP:经典的主备入口方案 <a class="header-anchor" href="#keepalived-vip-经典的主备入口方案" aria-label="Permalink to &quot;Keepalived + VIP:经典的主备入口方案&quot;">​</a></h3><p>Keepalived 是 Linux 上常用的主备实现工具:</p><ul><li><strong>VIP(Virtual IP)</strong>:一个虚拟 IP 地址,平时挂在主节点上</li><li>主备节点之间通过 VRRP 协议发送心跳</li><li>主节点心跳停止后,备节点接管 VIP</li><li>客户端始终访问同一个 VIP,后端切换对客户端透明</li></ul><div class="mermaid-diagram" data-mermaid-code="sequenceDiagram%0A%20%20participant%20C%20as%20%E5%AE%A2%E6%88%B7%E7%AB%AF%0A%20%20participant%20V%20as%20VIP%2010.0.0.100%0A%20%20participant%20P%20as%20%E4%B8%BB%2010.0.0.10%0A%20%20participant%20B%20as%20%E5%A4%87%2010.0.0.11%0A%0A%20%20Note%20over%20P%2CB%3A%20%E5%B9%B3%E6%97%B6%3Cbr%2F%3EVIP%20%E5%9C%A8%E4%B8%BB%E8%8A%82%E7%82%B9%2C%E4%B8%BB%E8%8A%82%E7%82%B9%E5%AE%9A%E6%9C%9F%E5%8F%91%E5%BF%83%E8%B7%B3%0A%20%20C-%3E%3EV%3A%20%E8%AF%B7%E6%B1%82%0A%20%20V-%3E%3EP%3A%20%E5%AE%9E%E9%99%85%E5%88%B0%E4%B8%BB%E8%8A%82%E7%82%B9%0A%20%20P--%3E%3EV%3A%20%E5%93%8D%E5%BA%94%0A%0A%20%20Note%20over%20P%3A%20%E4%B8%BB%E8%8A%82%E7%82%B9%E5%AE%95%E6%9C%BA%0A%20%20Note%20over%20B%3A%20%E5%A4%87%E8%8A%82%E7%82%B9%E6%94%B6%E4%B8%8D%E5%88%B0%E5%BF%83%E8%B7%B3%3Cbr%2F%3E%E7%AD%89%E5%BE%85%20hold%20time%0A%20%20B-%3E%3EB%3A%20VIP%20%E6%BC%82%E7%A7%BB%E5%88%B0%E6%9C%AC%E6%9C%BA%0A%0A%20%20C-%3E%3EV%3A%20%E6%96%B0%E8%AF%B7%E6%B1%82%0A%20%20V-%3E%3EB%3A%20%E6%AD%A4%E6%97%B6%20VIP%20%E5%B7%B2%E7%BB%8F%E5%9C%A8%E5%A4%87%E8%8A%82%E7%82%B9%0A%20%20B--%3E%3EV%3A%20%E5%93%8D%E5%BA%94%0A"></div><h3 id="数据库主备切换的额外复杂度" tabindex="-1">数据库主备切换的额外复杂度 <a class="header-anchor" href="#数据库主备切换的额外复杂度" aria-label="Permalink to &quot;数据库主备切换的额外复杂度&quot;">​</a></h3><p>数据库主备切换比 VIP 漂移复杂得多,需要确认:</p><table tabindex="0"><thead><tr><th>检查项</th><th>含义</th></tr></thead><tbody><tr><td>复制进度</td><td>主库最新的数据是否已经同步到备库</td></tr><tr><td>备库状态</td><td>备库是否处于可写模式</td></tr><tr><td>旧主隔离</td><td>旧主必须切换为只读或下线,避免接收新写入</td></tr><tr><td>应用连接刷新</td><td>应用的连接池可能还连着旧主,需要触发重连</td></tr></tbody></table><p>漏掉任何一项都可能造成数据不一致——例如旧主没正确隔离,应用继续往旧主写入,新主上没有这些数据。</p><h2 id="三、故障发现机制" tabindex="-1">三、故障发现机制 <a class="header-anchor" href="#三、故障发现机制" aria-label="Permalink to &quot;三、故障发现机制&quot;">​</a></h2><p>高可用系统必须先<strong>发现</strong>故障,才能做切换。故障发现的常见机制:</p><table tabindex="0"><thead><tr><th>机制</th><th>关注内容</th></tr></thead><tbody><tr><td>心跳(Heartbeat)</td><td>节点之间定期发包,确认对方还活着</td></tr><tr><td>健康检查</td><td>入口层定期探测后端,判断是否能处理请求</td></tr><tr><td>Leader 选举</td><td>多个节点投票选出一个主节点</td></tr><tr><td>仲裁(Quorum)</td><td>多数派同意才能做决定,避免脑裂</td></tr><tr><td>外部协调</td><td>etcd / ZooKeeper 提供分布式锁、租约</td></tr><tr><td>监控告警</td><td>从错误率、延迟、资源使用率发现异常</td></tr></tbody></table><h3 id="心跳的关键陷阱-网络分区" tabindex="-1">心跳的关键陷阱:网络分区 <a class="header-anchor" href="#心跳的关键陷阱-网络分区" aria-label="Permalink to &quot;心跳的关键陷阱:网络分区&quot;">​</a></h3><p><strong>心跳失败不等于对方真的死了——可能只是中间网络断了</strong>。这种情况下:</p><p><img src="'+n+`" alt="网络分区会导致脑裂，需要仲裁机制"></p><ul><li>主节点本身正常,与客户端的连接也正常</li><li>但主备之间的心跳网络断了</li><li>备节点收不到心跳,以为主节点死了</li><li>备节点抢主,与原主形成&quot;双主&quot;</li><li>客户端有的请求落到旧主,有的落到新主,数据分散</li></ul><p>这就是<strong>网络分区导致的脑裂</strong>。分布式系统的核心难题之一就是处理这种&quot;无法区分网络故障与节点故障&quot;的场景。</p><h3 id="避免脑裂的几种机制" tabindex="-1">避免脑裂的几种机制 <a class="header-anchor" href="#避免脑裂的几种机制" aria-label="Permalink to &quot;避免脑裂的几种机制&quot;">​</a></h3><table tabindex="0"><thead><tr><th>机制</th><th>工作方式</th></tr></thead><tbody><tr><td>仲裁节点</td><td>引入第三方节点投票,主备 + 仲裁三方协商</td></tr><tr><td>Quorum(法定人数)</td><td>需要多数派(N/2 + 1)同意才能切换</td></tr><tr><td>租约(Lease)</td><td>主节点必须定期向仲裁服务续约,续约失败自动失效</td></tr><tr><td>Fencing(隔离)</td><td>切换前主动断电/隔离旧主,确保它无法再写</td></tr><tr><td>外部锁</td><td>通过 etcd/ZooKeeper 持有的锁决定谁是主</td></tr></tbody></table><h3 id="quorum-为什么是奇数" tabindex="-1">Quorum 为什么是奇数 <a class="header-anchor" href="#quorum-为什么是奇数" aria-label="Permalink to &quot;Quorum 为什么是奇数&quot;">​</a></h3><p>Raft、Paxos 这类共识算法的 Quorum 通常要求&quot;多数派&quot;,所以<strong>集群节点数推荐奇数</strong>(3、5、7):</p><table tabindex="0"><thead><tr><th>集群大小</th><th>多数派</th><th>可容忍故障</th></tr></thead><tbody><tr><td>3</td><td>2</td><td>1 个</td></tr><tr><td>5</td><td>3</td><td>2 个</td></tr><tr><td>7</td><td>4</td><td>3 个</td></tr></tbody></table><p>偶数(如 4)的情况下:多数派是 3,可容忍故障 1 个——与 3 节点效果一样,但多了一台机器的成本。所以 etcd、ZooKeeper、Consul 等都推荐部署 3/5/7 节点。</p><h3 id="切换后的验证" tabindex="-1">切换后的验证 <a class="header-anchor" href="#切换后的验证" aria-label="Permalink to &quot;切换后的验证&quot;">​</a></h3><p>切换完成后,<strong>不能仅看入口能否访问就认为恢复了</strong>——必须做实际的写入验证:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 1. 入口能访问</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://api.example.com/healthz</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 2. 关键路径能写入</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -X</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> POST</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://api.example.com/api/test_write</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 3. 错误率回落到正常</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 看监控面板</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 4. 旧主已隔离,不再接收写入</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 检查旧主的连接数、SQL 日志,确认无新连接</span></span></code></pre></div><p>仅看入口可达就宣布&quot;已恢复&quot;是常见误判——可能新主还在初始化、复制还没追上、连接池还连旧主,真实业务还没恢复。</p><h2 id="四、集群形态" tabindex="-1">四、集群形态 <a class="header-anchor" href="#四、集群形态" aria-label="Permalink to &quot;四、集群形态&quot;">​</a></h2><p><strong>&quot;集群&quot;在不同组件里含义差异巨大</strong>,不能用统一思路理解。</p><table tabindex="0"><thead><tr><th>类型</th><th>工作方式</th></tr></thead><tbody><tr><td>Web/应用集群</td><td>多个无状态实例,前面负载均衡分发请求</td></tr><tr><td>Redis Cluster</td><td>数据按 slot 分散到不同节点,每节点负责一部分 key</td></tr><tr><td>Kafka 集群</td><td>Topic 的 partition 分布到多个 broker,消费者按 group 分担</td></tr><tr><td>数据库集群</td><td>主从、组复制(MGR)、分片、多主——模型多种多样</td></tr><tr><td>Elasticsearch</td><td>数据按 shard 分片,每个 shard 有副本</td></tr><tr><td>Kubernetes 集群</td><td>控制面调度,工作节点承载 Pod</td></tr><tr><td>etcd / ZooKeeper</td><td>一致性集群,强同步</td></tr></tbody></table><h3 id="无状态服务做集群-最简单" tabindex="-1">无状态服务做集群:最简单 <a class="header-anchor" href="#无状态服务做集群-最简单" aria-label="Permalink to &quot;无状态服务做集群:最简单&quot;">​</a></h3><p>无状态服务的集群最容易做:</p><ul><li>任何实例处理任何请求都一样(状态都在外部数据库/缓存)</li><li>加一个实例 = 多一个工作者</li><li>减一个实例 = 少一个工作者,流量自动转移到其他实例</li><li>实例之间完全等价,挂一个不影响其他</li></ul><p>无状态服务的横向扩展可以无限继续——直到数据库等其他层成为瓶颈。</p><h3 id="有状态服务做集群-难得多" tabindex="-1">有状态服务做集群:难得多 <a class="header-anchor" href="#有状态服务做集群-难得多" aria-label="Permalink to &quot;有状态服务做集群:难得多&quot;">​</a></h3><p>有状态服务的集群需要回答一系列问题:</p><ul><li>数据放在哪个节点?(分片策略)</li><li>谁能写?(主从模型 vs 多主模型)</li><li>副本同步到什么程度算&quot;提交&quot;?(同步/半同步/异步)</li><li>节点坏了由谁接管?(故障转移机制)</li><li>节点新加入时怎么补数据?(数据再平衡)</li><li>客户端怎么知道连哪个节点?(路由层)</li></ul><p><strong>不同有状态服务的集群模型完全不同</strong>:</p><ul><li><strong>Redis Cluster</strong>:数据按 slot 分散,每节点一部分。客户端通过 MOVED 重定向找到正确节点</li><li><strong>Kafka</strong>:Topic 分 partition,每 partition 有 leader 和 follower。Producer 按 partition 路由</li><li><strong>MySQL</strong>:主从、MGR(组复制)、分片(Vitess)各有取舍</li><li><strong>etcd</strong>:Raft 一致性,所有节点都有完整数据,写操作必须多数派确认</li></ul><p><strong>有状态服务的运维比无状态服务难得多</strong>——不能简单类比。MySQL 集群的故障处理思路不能套用到 Kafka 集群,反之亦然。每种有状态系统都需要专门学习其内部机制。</p><h2 id="五、数据一致性" tabindex="-1">五、数据一致性 <a class="header-anchor" href="#五、数据一致性" aria-label="Permalink to &quot;五、数据一致性&quot;">​</a></h2><p>应用层的高可用相对简单(无状态),<strong>数据层的高可用要面对一致性问题</strong>。</p><p><img src="`+l+`" alt="复制延迟会造成写后立即读不一致"></p><h3 id="一致性问题的常见表现" tabindex="-1">一致性问题的常见表现 <a class="header-anchor" href="#一致性问题的常见表现" aria-label="Permalink to &quot;一致性问题的常见表现&quot;">​</a></h3><table tabindex="0"><thead><tr><th>场景</th><th>用户侧表现</th></tr></thead><tbody><tr><td>主从复制延迟</td><td>刚提交的数据,马上查列表查不到</td></tr><tr><td>主库故障切换</td><td>故障前几秒的数据丢失(还没同步就切了)</td></tr><tr><td>多主写入冲突</td><td>两个地方同时改同一记录,结果不可预测</td></tr><tr><td>网络分区</td><td>部分客户端访问旧主,部分访问新主</td></tr><tr><td>缓存与数据库不一致</td><td>数据库改了,但缓存还是旧值</td></tr></tbody></table><h3 id="写后立即读-的经典坑" tabindex="-1">&quot;写后立即读&quot;的经典坑 <a class="header-anchor" href="#写后立即读-的经典坑" aria-label="Permalink to &quot;&quot;写后立即读&quot;的经典坑&quot;">​</a></h3><p>读写分离场景下最常见的体验问题:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户修改头像:写到主库</span></span>
<span class="line"><span>0.1 秒后用户刷新个人页:读请求路由到从库(刚好选中)</span></span>
<span class="line"><span>从库还没同步过来,读到旧头像</span></span>
<span class="line"><span>用户:&quot;修改没生效?&quot;</span></span></code></pre></div><p>处理方式:</p><table tabindex="0"><thead><tr><th>方案</th><th>说明</th></tr></thead><tbody><tr><td>强制读主</td><td>写操作后短时间内的同用户读请求,强制打主库</td></tr><tr><td>应用层缓存</td><td>写成功后,在应用内存中保留最新值短时间</td></tr><tr><td>Session 一致性</td><td>同一用户的请求保证看到自己最近写的(read-your-writes)</td></tr><tr><td>业务侧避免</td><td>UI 设计上让用户不立即看到列表(写成功后跳转到详情页)</td></tr></tbody></table><h3 id="一致性模型与可用性的取舍" tabindex="-1">一致性模型与可用性的取舍 <a class="header-anchor" href="#一致性模型与可用性的取舍" aria-label="Permalink to &quot;一致性模型与可用性的取舍&quot;">​</a></h3><p><strong>CAP 定理</strong>指出:分布式系统在网络分区时,<strong>一致性(Consistency)和可用性(Availability)二选一</strong>。</p><table tabindex="0"><thead><tr><th>选择</th><th>含义</th><th>典型系统</th></tr></thead><tbody><tr><td>CP</td><td>优先保证一致性,网络分区时拒绝服务</td><td>etcd、ZooKeeper、HBase</td></tr><tr><td>AP</td><td>优先保证可用性,接受暂时的不一致</td><td>Cassandra、DynamoDB</td></tr></tbody></table><p>业务系统大多采用 AP + 最终一致性的折中——可用性优先,允许短暂不一致,但保证最终所有副本会同步到一致状态。强一致性场景(金融转账)用 CP 系统或者通过事务保证。</p><h3 id="多主架构的复杂度" tabindex="-1">多主架构的复杂度 <a class="header-anchor" href="#多主架构的复杂度" aria-label="Permalink to &quot;多主架构的复杂度&quot;">​</a></h3><p>多主(每个数据中心都能写)能提供最高可用性,但<strong>写冲突的处理极其复杂</strong>:</p><ul><li>同一记录在两地同时被修改,以谁为准?</li><li>&quot;最后写入获胜&quot;会丢失部分修改</li><li>CRDT(无冲突复制数据类型)只能解决特定数据结构</li><li>业务层定义合并规则,成本高且容易出错</li></ul><p>绝大多数业务系统选择<strong>单主 + 多从</strong>而非多主——单主架构的写冲突天然不存在,工程复杂度低得多。多主架构主要用于全球级业务(跨大洲数据中心)、对可用性要求极高的特殊场景。</p><h2 id="六、高可用的成本观与分级投入" tabindex="-1">六、高可用的成本观与分级投入 <a class="header-anchor" href="#六、高可用的成本观与分级投入" aria-label="Permalink to &quot;六、高可用的成本观与分级投入&quot;">​</a></h2><p><strong>不同系统的高可用投入应当不同</strong>——不能所有系统都按最高标准做。</p><table tabindex="0"><thead><tr><th>系统类型</th><th>高可用投入</th></tr></thead><tbody><tr><td>内部低频工具(运维平台、内部 Wiki)</td><td>备份 + 监控 + 快速重建文档,可以容忍数小时不可用</td></tr><tr><td>一般业务系统(普通 SaaS)</td><td>主备/集群 + 跨机房备份,可用性 99.9%</td></tr><tr><td>核心交易系统(支付、电商)</td><td>多机房 + 多副本 + 实时同步 + 灰度发布 + 限流熔断,可用性 99.95%+</td></tr><tr><td>金融核心系统(银行)</td><td>异地双活 + 实时容灾 + 严格事务,可用性 99.99%+</td></tr></tbody></table><p><strong>把所有系统都按金融核心标准建设,成本承受不住</strong>——服务器、网络、人力都会增加数倍。合理做法是按业务重要性分级,核心系统重点投入,边缘系统保留基础能力。</p><h3 id="衡量高可用的指标" tabindex="-1">衡量高可用的指标 <a class="header-anchor" href="#衡量高可用的指标" aria-label="Permalink to &quot;衡量高可用的指标&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指标</th><th>含义</th></tr></thead><tbody><tr><td>可用性(SLA)</td><td>一段时间内系统可用时间占比(如 99.95%)</td></tr><tr><td>RTO(Recovery Time Objective)</td><td>故障到恢复的目标时间</td></tr><tr><td>RPO(Recovery Point Objective)</td><td>允许丢失的数据时间窗口</td></tr><tr><td>MTBF(Mean Time Between Failures)</td><td>平均故障间隔</td></tr><tr><td>MTTR(Mean Time To Repair)</td><td>平均修复时间</td></tr></tbody></table><p>可用性的换算参考:</p><table tabindex="0"><thead><tr><th>SLA</th><th>年不可用时长</th><th>月不可用时长</th></tr></thead><tbody><tr><td>99%</td><td>3.65 天</td><td>7.2 小时</td></tr><tr><td>99.9%</td><td>8.77 小时</td><td>43.8 分钟</td></tr><tr><td>99.95%</td><td>4.38 小时</td><td>21.9 分钟</td></tr><tr><td>99.99%</td><td>52.6 分钟</td><td>4.4 分钟</td></tr><tr><td>99.999%</td><td>5.26 分钟</td><td>26.3 秒</td></tr></tbody></table><p>每多一个 9,所需的工程投入呈指数级增长。99.999%(五个 9)通常需要异地多活、专业团队 24 小时值守、自动化运维体系——成本极高,只有金融、电信等关键基础设施才需要。</p><h2 id="七、恢复确认与演练" tabindex="-1">七、恢复确认与演练 <a class="header-anchor" href="#七、恢复确认与演练" aria-label="Permalink to &quot;七、恢复确认与演练&quot;">​</a></h2><h3 id="切换后的检查项" tabindex="-1">切换后的检查项 <a class="header-anchor" href="#切换后的检查项" aria-label="Permalink to &quot;切换后的检查项&quot;">​</a></h3><p>故障切换完成后,留下能审计的记录,便于复盘与确认:</p><table tabindex="0"><thead><tr><th>检查项</th><th>看什么</th></tr></thead><tbody><tr><td>入口</td><td>域名、VIP、负载均衡是否指向新节点</td></tr><tr><td>应用</td><td>错误率、延迟、实例重启情况、日志异常</td></tr><tr><td>数据库</td><td>新主可写、旧主只读或下线、复制链路状态</td></tr><tr><td>用户路径</td><td>登录、查询、提交、支付、后台任务是否全部恢复</td></tr><tr><td>监控</td><td>告警是否消除,有无残留错误</td></tr><tr><td>数据完整性</td><td>切换前后的数据一致性,有无数据丢失</td></tr></tbody></table><h3 id="关键时间点的记录" tabindex="-1">关键时间点的记录 <a class="header-anchor" href="#关键时间点的记录" aria-label="Permalink to &quot;关键时间点的记录&quot;">​</a></h3><p>切换过程的时间点要精确记录:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>14:23:45  监控告警 - 主库连接失败</span></span>
<span class="line"><span>14:23:50  人工确认主库不可达</span></span>
<span class="line"><span>14:24:10  触发自动切换</span></span>
<span class="line"><span>14:24:25  备库提升为新主,VIP 漂移完成</span></span>
<span class="line"><span>14:24:30  应用第一个写入成功</span></span>
<span class="line"><span>14:25:00  错误率回落正常</span></span>
<span class="line"><span>14:30:00  旧主被隔离,确认无新连接</span></span></code></pre></div><p>这些精确到秒/分钟的时间点,在复盘 RTO/RPO 时远比一句&quot;已恢复&quot;有价值。</p><h3 id="高可用演练-验证机制真的有效" tabindex="-1">高可用演练:验证机制真的有效 <a class="header-anchor" href="#高可用演练-验证机制真的有效" aria-label="Permalink to &quot;高可用演练:验证机制真的有效&quot;">​</a></h3><p><strong>未演练过的高可用机制,真出事时大概率不会按预期工作</strong>——配置漂移、依赖变化、人员变动都可能让原本可用的机制失效。</p><p>定期演练的项目:</p><table tabindex="0"><thead><tr><th>演练项</th><th>频率</th></tr></thead><tbody><tr><td>主备切换(数据库、Redis)</td><td>每季度</td></tr><tr><td>节点宕机模拟(Chaos Engineering)</td><td>每月</td></tr><tr><td>备份恢复</td><td>每季度</td></tr><tr><td>跨机房切换</td><td>每半年</td></tr><tr><td>完整灾备演练</td><td>每年</td></tr></tbody></table><p><strong>&quot;演练过的机制&quot;才是真正的高可用机制</strong>。备份从没恢复过、切换从没切过、灾备机房从没接管过——这些都不是真实的高可用,只是文档里的&quot;高可用&quot;。Netflix 的 Chaos Monkey 就是把这一原则做到极致:<strong>在生产环境随机杀实例,强制系统具备真正的容错能力</strong>。</p>`,113)])])}const q=a(o,[["render",h]]);export{A as __pageData,q as default};
